#!/usr/bin/env bash
# Generate / update the Homebrew formula for aura.
#
# Called by the release CI job after macOS tarballs are built and their
# SHA256 checksums are known. Writes a complete Formula/aura.rb file
# into a locally checked-out hamiorg/homebrew-aura repo.
#
# Usage:
#   brew.sh <version> <sha256-arm64> <sha256-x86_64> <tap-dir>
#
# Arguments:
#   version        Git tag, e.g. v0.1.0-alpha.1
#   sha256-arm64   SHA256 hex of aura-{version}-macos-arm64.tar.gz
#   sha256-x86_64  SHA256 hex of aura-{version}-macos-x86_64.tar.gz
#   tap-dir        Path to a checked-out hamiorg/homebrew-aura clone
#
# Example:
#   bash dist/package/brew.sh v0.1.0-alpha.1 abc123... def456... ./tap

set -euo pipefail

VERSION="${1:?Usage: brew.sh <version> <sha256-arm64> <sha256-x86_64> <tap-dir>}"
SHA_ARM64="${2:?sha256-arm64 required}"
SHA_X86_64="${3:?sha256-x86_64 required}"
TAP_DIR="${4:?tap-dir required}"

# Strip the leading 'v' for the Homebrew version field.
VERSION_PLAIN="${VERSION#v}"

FORMULA="${TAP_DIR}/Formula/aura.rb"
mkdir -p "${TAP_DIR}/Formula"

# Write the complete formula. Using a heredoc with quoted delimiter
# ('FORMULA_EOF') so that $(...) substitutions inside are NOT expanded
# by the shell — only the explicit ${VAR} references at the top are.
cat > "${FORMULA}" << FORMULA_EOF
# Generated by dist/package/brew.sh — do not edit manually.
# Update by pushing a new release tag to hamiorg/aura.
class Aura < Formula
  desc "AURA toolchain CLI -- compile .aura source to .atom/.hami/.atlas"
  homepage "https://hami.aduki.org"
  version "${VERSION_PLAIN}"
  license "MIT"

  on_macos do
    on_arm do
      url "https://github.com/hamiorg/aura/releases/download/${VERSION}/aura-${VERSION}-macos-arm64.tar.gz"
      sha256 "${SHA_ARM64}"
    end

    on_intel do
      url "https://github.com/hamiorg/aura/releases/download/${VERSION}/aura-${VERSION}-macos-x86_64.tar.gz"
      sha256 "${SHA_X86_64}"
    end
  end

  def install
    bin.install "aura"
  end

  test do
    assert_match version.to_s, shell_output("#{bin}/aura --version")
  end
end
FORMULA_EOF

echo "[brew] wrote ${FORMULA} for ${VERSION}"
echo "[brew] arm64   sha256: ${SHA_ARM64}"
echo "[brew] x86_64  sha256: ${SHA_X86_64}"
